import type { PublicCard } from '../../../types';

export const gcseProblemSolvingCards: PublicCard[] = [
  // NUMBER TRICKS (1-30)
  { id: 'dc-gcse-psolve-0001', deck_id: 'deck-gcse-problem-solving', front: 'Quick trick: multiply any number by 25.', back: 'Divide by 4 (same as ÷2 then ÷2), then multiply by 100.\nExample: 36 × 25 = 36 ÷ 4 × 100 = 9 × 100 = 900\n\nGCSE Tip: 25 = 100÷4. Much faster than long multiplication in non-calculator papers.', sort_order: 1 },
  { id: 'dc-gcse-psolve-0002', deck_id: 'deck-gcse-problem-solving', front: 'Quick trick: multiply any number by 125.', back: 'Divide by 8, then multiply by 1000.\nExample: 24 × 125 = 24 ÷ 8 × 1000 = 3 × 1000 = 3000\n\nGCSE Tip: 125 = 1000÷8. Spot these shortcuts to save time on non-calculator papers.', sort_order: 2 },
  { id: 'dc-gcse-psolve-0003', deck_id: 'deck-gcse-problem-solving', front: 'How to square any number ending in 5 quickly.', back: 'Take the tens digit n, calculate n(n+1), then append 25.\nExample: 75² → n=7, 7×8=56, answer = 5625\nExample: 35² → n=3, 3×4=12, answer = 1225\n\nGCSE Tip: Works for any number ending in 5. Verify: 35²=1225 ✓', sort_order: 3 },
  { id: 'dc-gcse-psolve-0004', deck_id: 'deck-gcse-problem-solving', front: 'Divisibility trick: when is a number divisible by 9?', back: 'A number is divisible by 9 if the sum of its digits is divisible by 9.\nExample: 738 → 7+3+8=18, 18÷9=2 ✓ divisible by 9\nExample: 452 → 4+5+2=11, not divisible by 9 ✗\n\nGCSE Tip: Also works for 3: digit sum divisible by 3 → whole number divisible by 3.', sort_order: 4 },
  { id: 'dc-gcse-psolve-0005', deck_id: 'deck-gcse-problem-solving', front: 'How to estimate a calculation to check your answer.', back: 'Round all numbers to 1 significant figure, then calculate.\nExample: 382 × 47 → 400 × 50 = 20000. Exact = 17954. Estimate confirms correct order of magnitude.\n\nGCSE Tip: Estimation catches errors like misplaced decimals. Always estimate before reaching for a calculator.', sort_order: 5 },
  { id: 'dc-gcse-psolve-0006', deck_id: 'deck-gcse-problem-solving', front: 'Finding 15% quickly without a calculator.', back: '10% + 5% (half of 10%)\nExample: 15% of £84 → 10%=£8.40, 5%=£4.20, total=£12.60\n\nGCSE Tip: Break percentages into chunks of 10%, 5%, 1%. Combine as needed.', sort_order: 6 },
  { id: 'dc-gcse-psolve-0007', deck_id: 'deck-gcse-problem-solving', front: 'How to find the original price after a percentage change.', back: 'Identify what percentage the given price REPRESENTS, then divide.\nExample: Price after 30% reduction = £56. This is 70%. Original = 56 ÷ 0.7 = £80\n\nGCSE Tip: Never add/subtract the percentage from the reduced price. Always divide by the multiplier.', sort_order: 7 },
  { id: 'dc-gcse-psolve-0008', deck_id: 'deck-gcse-problem-solving', front: 'Trick to quickly convert a fraction to a percentage.', back: 'Divide numerator by denominator, multiply by 100.\nExample: 7/8 = 7÷8 = 0.875 = 87.5%\nShortcut: if denominator divides into 100 easily, scale up.\nExample: 3/4 → ×25/25 = 75/100 = 75%\n\nGCSE Tip: Denominators 2,4,5,10,20,25,50 convert easily by scaling to 100.', sort_order: 8 },
  { id: 'dc-gcse-psolve-0009', deck_id: 'deck-gcse-problem-solving', front: 'How to spot whether to use simple or compound interest.', back: 'Simple: interest calculated on original amount only. "£x per year" or "simple interest".\nCompound: interest on accumulated total. "3% per annum" or "invested" usually implies compound.\n\nGCSE Tip: Most real-world scenarios (savings, loans, depreciation) use compound interest unless stated otherwise.', sort_order: 9 },
  { id: 'dc-gcse-psolve-0010', deck_id: 'deck-gcse-problem-solving', front: 'How to check if a fraction is in its simplest form.', back: 'Find the HCF of numerator and denominator. If HCF = 1, it\'s already in simplest form.\nExample: 18/24 — HCF(18,24)=6. 18÷6=3, 24÷6=4. Simplest form: 3/4\n\nGCSE Tip: Keep dividing both by common factors until HCF = 1.', sort_order: 10 },
  { id: 'dc-gcse-psolve-0011', deck_id: 'deck-gcse-problem-solving', front: 'Trick for multiplying decimals: ignore the decimal point first.', back: 'Multiply as whole numbers, then count total decimal places.\nExample: 0.06 × 0.7 → 6×7=42, total d.p. = 2+1 = 3, answer = 0.042\n\nGCSE Tip: Count decimal places in EACH factor, add them for the answer. Then place the point.', sort_order: 11 },
  { id: 'dc-gcse-psolve-0012', deck_id: 'deck-gcse-problem-solving', front: 'How to order fractions without a common denominator.', back: 'Convert all to decimals (or to a common denominator).\nExample: Order 2/3, 3/5, 7/10.\n2/3≈0.667, 3/5=0.6, 7/10=0.7\nOrder: 3/5 < 2/3 < 7/10\n\nGCSE Tip: Decimal conversion is fastest. Use long division if not obvious.', sort_order: 12 },
  { id: 'dc-gcse-psolve-0013', deck_id: 'deck-gcse-problem-solving', front: 'When should you leave an answer in surd form?', back: 'Leave in surd form when the question says "exact answer", "in terms of π", or "without a calculator".\nExact surds: √12 = 2√3, not 3.464...\n\nGCSE Tip: Surd = exact. Decimal = approximate. If they want "exact", use surds or π.', sort_order: 13 },
  { id: 'dc-gcse-psolve-0014', deck_id: 'deck-gcse-problem-solving', front: 'How to quickly find the LCM of two numbers.', back: 'LCM = (a × b) ÷ HCF(a, b)\nExample: LCM(8, 12) = (8×12) ÷ 4 = 96 ÷ 4 = 24\n\nGCSE Tip: Use this formula when the prime factorisation method feels slow. Always find HCF first.', sort_order: 14 },
  { id: 'dc-gcse-psolve-0015', deck_id: 'deck-gcse-problem-solving', front: 'How to handle a "best value" problem (which pack is cheapest per unit?).', back: 'Find the cost per unit for each option.\nExample: 6 for £1.50 = 25p each; 8 for £1.92 = 24p each → 8-pack is better value.\n\nGCSE Tip: Divide price by quantity. Always compare the same unit. Watch for trick questions where larger ≠ cheaper.', sort_order: 15 },
  { id: 'dc-gcse-psolve-0016', deck_id: 'deck-gcse-problem-solving', front: 'How to handle upper and lower bounds in calculations.', back: 'Max result: use upper bounds for values being added/multiplied, lower bounds for values being subtracted/divided.\nMin result: opposite.\nExample: Max area = upper bound of length × upper bound of width.\n\nGCSE Tip: Think about which combination gives the largest (or smallest) possible result.', sort_order: 16 },
  { id: 'dc-gcse-psolve-0017', deck_id: 'deck-gcse-problem-solving', front: 'Trick: how to subtract mentally using "adding on".', back: 'Instead of 83−47, count up from 47 to 83.\n47 → 50 (+3), 50 → 83 (+33), total = +36\nSo 83−47 = 36\n\nGCSE Tip: "Shop assistant" method. Easier to add up than borrow/carry in subtraction.', sort_order: 17 },
  { id: 'dc-gcse-psolve-0018', deck_id: 'deck-gcse-problem-solving', front: 'How to use the "unitary method" to solve proportion problems efficiently.', back: '1. Find the value for 1 unit first.\n2. Scale up (or down) to the required amount.\nExample: 5 bags cost £8.50. Cost of 3 bags?\n1 bag = £8.50÷5 = £1.70. 3 bags = £1.70×3 = £5.10\n\nGCSE Tip: Unitary method works for any direct proportion problem.', sort_order: 18 },
  { id: 'dc-gcse-psolve-0019', deck_id: 'deck-gcse-problem-solving', front: 'How to recognise when a problem involves inverse proportion.', back: 'Inverse proportion: more of one thing means less of another.\nKey phrases: "more workers, fewer days", "faster speed, less time", "greater force, less pressure".\nSetup: quantity₁ × quantity₂ = constant (k)\n\nGCSE Tip: If doubling one halves the other → inverse. If doubling one doubles the other → direct.', sort_order: 19 },
  { id: 'dc-gcse-psolve-0020', deck_id: 'deck-gcse-problem-solving', front: 'Trick: how to calculate a percentage increase/decrease in one step.', back: 'Multiply by the decimal multiplier.\nIncrease by 18% → ×1.18\nDecrease by 35% → ×0.65\nChain: increase 20% then decrease 15% → ×1.20×0.85 = ×1.02 (2% net increase)\n\nGCSE Tip: Chain multipliers for successive changes. Never add/subtract percentages directly.', sort_order: 20 },
  { id: 'dc-gcse-psolve-0021', deck_id: 'deck-gcse-problem-solving', front: 'How to decide if a number is rational or irrational.', back: 'Rational: can be written as p/q (fraction of integers). Includes terminating and recurring decimals.\nIrrational: cannot be written as a fraction. Includes √(non-perfect squares), π, e.\nExamples: √9=3 rational; √10 irrational; 0.333...=1/3 rational\n\nGCSE Tip: Any surd that doesn\'t simplify to a whole number is irrational.', sort_order: 21 },
  { id: 'dc-gcse-psolve-0022', deck_id: 'deck-gcse-problem-solving', front: 'How to find the nth term when given a quadratic sequence.', back: '1. Find 1st differences (not constant).\n2. Find 2nd differences (should be constant = 2a).\n3. a = 2nd difference ÷ 2.\n4. Subtract an² from sequence to get linear part.\n5. Find linear nth term of the remainder.\nExample: 3,8,15,24 → 2nd diff=2 → a=1 → subtract n²: 2,4,6,8 → 2n → nth term = n²+2n\n\nGCSE Tip: 2nd difference is always constant for quadratics.', sort_order: 22 },
  { id: 'dc-gcse-psolve-0023', deck_id: 'deck-gcse-problem-solving', front: 'How to recognise which form of standard form answer to give.', back: 'Standard form: A × 10ⁿ where 1 ≤ A < 10, n is an integer.\nCommon errors:\n- 12 × 10³ wrong (12 ≥ 10) → 1.2 × 10⁴\n- 0.5 × 10⁶ wrong (0.5 < 1) → 5 × 10⁵\n\nGCSE Tip: Always check: is A between 1 and 10? If not, adjust n accordingly.', sort_order: 23 },
  { id: 'dc-gcse-psolve-0024', deck_id: 'deck-gcse-problem-solving', front: 'Trick: how to find compound interest multiplier for a percentage that isn\'t easy.', back: 'Multiplier = (1 + r/100)ⁿ or (1 − r/100)ⁿ\nExample: £4000 at 2.5% for 3 years = 4000 × 1.025³\n1.025³ = 1.025 × 1.025 × 1.025 = 1.07689...\n4000 × 1.07689 = £4307.56\n\nGCSE Tip: Write out the multiplier fully before calculating to avoid errors.', sort_order: 24 },
  { id: 'dc-gcse-psolve-0025', deck_id: 'deck-gcse-problem-solving', front: 'How to handle a problem where the answer must be a whole number.', back: 'After calculating, consider whether to round up or down based on context.\nExample: "How many buses are needed for 143 people, 52 per bus?" → 143÷52 = 2.75 → round UP to 3.\nExample: "How many complete metres of ribbon from 17.8m?" → round DOWN to 17.\n\nGCSE Tip: "How many?" or "Minimum number needed" → usually round up. "Complete" or "full" → round down.', sort_order: 25 },
  { id: 'dc-gcse-psolve-0026', deck_id: 'deck-gcse-problem-solving', front: 'Speed trick: mental maths for dividing by 5.', back: 'Dividing by 5 = multiplying by 2 then dividing by 10.\nExample: 370 ÷ 5 = 370 × 2 ÷ 10 = 740 ÷ 10 = 74\nExample: 135 ÷ 5 = 270 ÷ 10 = 27\n\nGCSE Tip: Since 5 = 10÷2, dividing by 5 is doubling then moving the decimal point left.', sort_order: 26 },
  { id: 'dc-gcse-psolve-0027', deck_id: 'deck-gcse-problem-solving', front: 'How to verify that a quadratic factorisation is correct.', back: 'Expand your factorised form and check it matches the original.\nExample: Check (2x+3)(x−4) = 2x²−8x+3x−12 = 2x²−5x−12 ✓\n\nGCSE Tip: Always expand to verify. Takes 30 seconds and can save you from losing all the marks.', sort_order: 27 },
  { id: 'dc-gcse-psolve-0028', deck_id: 'deck-gcse-problem-solving', front: 'How to identify whether a problem needs the mean, median or mode.', back: 'Mean: for continuous data without outliers; "average".\nMedian: when data has outliers (e.g. salaries); "middle value".\nMode: for categorical or discrete data; "most popular".\n\nGCSE Tip: Salary problems → median (Bill Gates in the room!). Shoe sizes → mode. Exam scores → mean.', sort_order: 28 },
  { id: 'dc-gcse-psolve-0029', deck_id: 'deck-gcse-problem-solving', front: 'Trick: how to multiply two numbers close to 100 quickly.', back: 'Example: 97 × 96\nDeficits from 100: 3 and 4\nLeft part: 97−4 = 93 (or 96−3 = 93)\nRight part: 3×4 = 12\nAnswer: 9312\n\nGCSE Tip: This is a mental arithmetic shortcut. Verify by estimating: ~100×100=10000, so 9312 is plausible.', sort_order: 29 },
  { id: 'dc-gcse-psolve-0030', deck_id: 'deck-gcse-problem-solving', front: 'How to check your answer is reasonable using number sense.', back: 'Ask: Does this answer make sense in context?\n- Area of a classroom ~50m², not 50cm² or 5000m².\n- Speed of a car ~60mph, not 6mph or 600mph.\n- Probability must be between 0 and 1.\n\nGCSE Tip: Sanity-check every answer. Wrong units or wrong order of magnitude costs easy marks.', sort_order: 30 },

  // ALGEBRA TRICKS (31-65)
  { id: 'dc-gcse-psolve-0031', deck_id: 'deck-gcse-problem-solving', front: 'Strategy: "working backwards" for inverse function problems.', back: 'To find f⁻¹, literally reverse the operations in reverse order.\nf(x): ×2, then +3. So f⁻¹: −3, then ÷2. f⁻¹(x) = (x−3)/2\n\nGCSE Tip: List the operations in order. Reverse both the order AND the operation (+ becomes −, × becomes ÷).', sort_order: 31 },
  { id: 'dc-gcse-psolve-0032', deck_id: 'deck-gcse-problem-solving', front: 'How to choose between factorising and the quadratic formula.', back: 'Try factorising first (quick, exact answers). If b²−4ac is not a perfect square, use the formula.\nFactorise when: coefficients are small and b²−4ac is a perfect square.\nFormula when: messy numbers, decimal or surd answers needed.\n\nGCSE Tip: Checking discriminant before factorising saves time.', sort_order: 32 },
  { id: 'dc-gcse-psolve-0033', deck_id: 'deck-gcse-problem-solving', front: 'Trick: how to solve simultaneous equations when both have large coefficients.', back: 'Scale both equations to eliminate one variable.\nExample: 5x+3y=19, 3x+2y=12\nMultiply eq1 ×2, eq2 ×3: 10x+6y=38, 9x+6y=36\nSubtract: x=2. Then y=(19−10)/3=3.\n\nGCSE Tip: Choose to eliminate the variable with the easiest-to-match coefficients.', sort_order: 33 },
  { id: 'dc-gcse-psolve-0034', deck_id: 'deck-gcse-problem-solving', front: 'How to set up an equation from a word problem.', back: '1. Name the unknown: "Let x = ..."\n2. Express all quantities in terms of x.\n3. Write the equation using the given condition.\n4. Solve, then check in context.\nExample: "I\'m 3 times older than my sister. Sum of ages = 24." x + 3x = 24 → x = 6.\n\nGCSE Tip: Defining the variable clearly prevents confusion mid-solution.', sort_order: 34 },
  { id: 'dc-gcse-psolve-0035', deck_id: 'deck-gcse-problem-solving', front: 'How to solve an equation with the unknown on both sides.', back: 'Collect all x terms on one side, all constants on the other.\nExample: 7x−4 = 3x+12\n7x−3x = 12+4\n4x = 16, x = 4\n\nGCSE Tip: Move SMALLER x coefficient to avoid negatives. Check by substituting back.', sort_order: 35 },
  { id: 'dc-gcse-psolve-0036', deck_id: 'deck-gcse-problem-solving', front: 'How to deal with algebraic fractions in equations.', back: 'Multiply through by the LCD (lowest common denominator) to clear all fractions.\nExample: x/3 + x/4 = 7. LCD=12. 4x + 3x = 84. 7x = 84. x = 12.\n\nGCSE Tip: Multiply every term (including those without fractions) by the LCD.', sort_order: 36 },
  { id: 'dc-gcse-psolve-0037', deck_id: 'deck-gcse-problem-solving', front: 'How to rearrange a formula with the unknown appearing twice.', back: 'Collect all terms with the unknown on one side, factorise, then divide.\nExample: Make x the subject: ax + b = cx + d\nax − cx = d − b\nx(a−c) = d−b\nx = (d−b)/(a−c)\n\nGCSE Tip: Factorise out the unknown, then divide. The unknown must appear only once in the answer.', sort_order: 37 },
  { id: 'dc-gcse-psolve-0038', deck_id: 'deck-gcse-problem-solving', front: 'How to use "difference of two squares" to factorise quickly.', back: 'a² − b² = (a+b)(a−b)\nSpot DTS: two perfect squares with a minus sign.\nExamples: x²−25 = (x+5)(x−5); 4x²−9 = (2x+3)(2x−3)\n\nGCSE Tip: Check for DTS before attempting the AC method. Much faster.', sort_order: 38 },
  { id: 'dc-gcse-psolve-0039', deck_id: 'deck-gcse-problem-solving', front: 'Strategy for proving algebraic statements: start from one side only.', back: 'Choose the more complex side. Simplify step by step until it equals the other side.\nNever move terms across the equals sign — that assumes what you\'re trying to prove.\n\nGCSE Tip: Write "LHS = ..." or "RHS = ..." and work towards the other side. State "= RHS" or "= LHS" at the end.', sort_order: 39 },
  { id: 'dc-gcse-psolve-0040', deck_id: 'deck-gcse-problem-solving', front: 'How to check if a value is in a sequence given its nth term formula.', back: 'Set the nth term formula = the value. Solve for n. If n is a positive integer → it IS a term.\nExample: nth term = 5n−3. Is 47 a term?\n5n−3=47 → 5n=50 → n=10 ✓ (integer) → Yes, it\'s the 10th term.\n\nGCSE Tip: Non-integer or negative n → the value is NOT in the sequence.', sort_order: 40 },
  { id: 'dc-gcse-psolve-0041', deck_id: 'deck-gcse-problem-solving', front: 'How to find where two graphs intersect without plotting.', back: 'Set the two equations equal to each other and solve.\nExample: y=x²+1 and y=2x+4.\nx²+1 = 2x+4 → x²−2x−3=0 → (x−3)(x+1)=0 → x=3 or x=−1.\nSubstitute to find y.\n\nGCSE Tip: Intersections = solutions of the simultaneous equations. Quadratic × linear → up to 2 intersections.', sort_order: 41 },
  { id: 'dc-gcse-psolve-0042', deck_id: 'deck-gcse-problem-solving', front: 'How to determine the number of solutions of a quadratic from the discriminant.', back: 'b²−4ac > 0 → 2 distinct real solutions\nb²−4ac = 0 → 1 repeated solution (touches x-axis)\nb²−4ac < 0 → no real solutions\n\nGCSE Tip: Calculate the discriminant before solving to plan your approach.', sort_order: 42 },
  { id: 'dc-gcse-psolve-0043', deck_id: 'deck-gcse-problem-solving', front: 'Trick: how to find the y-intercept of any graph instantly.', back: 'Substitute x = 0 into the equation.\nExamples: y=3x²−5x+2 → y=2\ny = (x+1)(x−3) → y = (1)(−3) = −3\n\nGCSE Tip: Setting x=0 always gives the y-intercept. Quick check for any curve.', sort_order: 43 },
  { id: 'dc-gcse-psolve-0044', deck_id: 'deck-gcse-problem-solving', front: 'How to find x-intercepts (roots) of a graph quickly.', back: 'Set y = 0 and solve.\ny = x²−5x+6 = 0 → (x−2)(x−3)=0 → x=2 and x=3\n\nGCSE Tip: Roots/x-intercepts/zeros all mean "where the graph crosses the x-axis" = set y=0.', sort_order: 44 },
  { id: 'dc-gcse-psolve-0045', deck_id: 'deck-gcse-problem-solving', front: 'How to sketch a cubic graph by factorising.', back: '1. Factorise fully (find all roots).\n2. Single root → graph crosses axis. Repeated root → graph touches and turns.\n3. Check sign of leading coefficient for overall shape (+x³ → goes bottom-left to top-right).\n\nGCSE Tip: Mark roots, y-intercept, and overall shape. You don\'t need to plot every point.', sort_order: 45 },
  { id: 'dc-gcse-psolve-0046', deck_id: 'deck-gcse-problem-solving', front: 'Strategy: how to solve problems involving function composition.', back: 'gf(x) means: apply f first, then apply g to the result.\nStep 1: Find f(x) for the given x value.\nStep 2: Use that result as the input for g.\nExample: f(x)=x+1, g(x)=x². gf(3)=g(f(3))=g(4)=16.\n\nGCSE Tip: Work inside-out. gf ≠ fg unless the functions happen to commute.', sort_order: 46 },
  { id: 'dc-gcse-psolve-0047', deck_id: 'deck-gcse-problem-solving', front: 'How to recognise a direct or inverse proportion graph.', back: 'Direct (y=kx): straight line through origin. y∝x²: curved upward through origin.\nInverse (y=k/x): hyperbola — never touches axes. Curves from top-left to bottom-right in 1st quadrant.\n\nGCSE Tip: Direct → through origin. Inverse → hyperbola with axes as asymptotes.', sort_order: 47 },
  { id: 'dc-gcse-psolve-0048', deck_id: 'deck-gcse-problem-solving', front: 'How to use trial and improvement efficiently to find a root.', back: '1. Find two integers where the function changes sign.\n2. Try the midpoint. Check sign.\n3. Narrow the interval. Repeat to required accuracy.\nExample: x³+x=20. Try x=2: 10. Too small. x=3: 30. Too big. Try 2.5: 18.1. Too small. Try 2.6: 20.2...\n\nGCSE Tip: Show all trials in a table. State the sign (+/−) to justify which interval to narrow.', sort_order: 48 },
  { id: 'dc-gcse-psolve-0049', deck_id: 'deck-gcse-problem-solving', front: 'How to solve exponential equations without logs (GCSE level).', back: 'Express both sides as powers of the same base, then equate indices.\nExample: 4^x = 32 → 2^(2x) = 2^5 → 2x = 5 → x = 2.5\n\nGCSE Tip: Convert both sides to the same prime base. Works when the answer is a simple fraction.', sort_order: 49 },
  { id: 'dc-gcse-psolve-0050', deck_id: 'deck-gcse-problem-solving', front: 'How to approach a "show that" algebra question.', back: '"Show that" means all steps must be shown clearly. The answer is given — your job is to prove it.\n1. Start with the given expression.\n2. Show each algebraic step.\n3. End with the exact target expression.\nNever start from the answer and work backwards.\n\nGCSE Tip: Every manipulation must be justified. Examiners penalise circular arguments.', sort_order: 50 },
  { id: 'dc-gcse-psolve-0051', deck_id: 'deck-gcse-problem-solving', front: 'Trick: how to expand triple brackets efficiently.', back: 'Expand two brackets first, then multiply by the third.\nExample: (x+1)(x+2)(x+3)\nStep 1: (x+1)(x+2) = x²+3x+2\nStep 2: (x²+3x+2)(x+3) = x³+3x²+3x²+9x+2x+6 = x³+6x²+11x+6\n\nGCSE Tip: Never try to expand all three at once. Two at a time is always safer.', sort_order: 51 },
  { id: 'dc-gcse-psolve-0052', deck_id: 'deck-gcse-problem-solving', front: 'How to find the equation of a line parallel to a given line.', back: 'Parallel lines have the SAME gradient.\nGiven y=3x+7, parallel line through (1,2):\nSame gradient m=3. Use y−2=3(x−1) → y=3x−1.\n\nGCSE Tip: Copy the gradient, then use y−y₁=m(x−x₁) with the new point.', sort_order: 52 },
  { id: 'dc-gcse-psolve-0053', deck_id: 'deck-gcse-problem-solving', front: 'How to find the equation of a perpendicular line.', back: 'Perpendicular gradient = negative reciprocal of original.\nGiven gradient 2/3, perpendicular = −3/2.\nThrough (4,1): y−1 = −(3/2)(x−4) → y = −(3/2)x + 7\n\nGCSE Tip: m₁ × m₂ = −1 for perpendicular lines. Flip the fraction and change the sign.', sort_order: 53 },
  { id: 'dc-gcse-psolve-0054', deck_id: 'deck-gcse-problem-solving', front: 'Strategy: what to do if a quadratic problem gives a negative solution that doesn\'t make sense.', back: 'In context, reject any solution that is impossible.\nExample: x = length of a rectangle, so x > 0. Reject x = −3.\nAlways state "x = −3 is rejected since length cannot be negative."\n\nGCSE Tip: Both solutions are mathematically valid. Context determines which to keep. Always explain your reasoning.', sort_order: 54 },
  { id: 'dc-gcse-psolve-0055', deck_id: 'deck-gcse-problem-solving', front: 'How to solve inequalities involving quadratics.', back: '1. Rearrange to ax²+bx+c ≤/≥ 0.\n2. Find roots by factorising or formula.\n3. Sketch the parabola.\n4. Read off where the curve is above/below zero.\nPositive x²: curve is < 0 BETWEEN roots, > 0 OUTSIDE roots.\n\nGCSE Tip: The sketch is essential — it shows which regions satisfy the inequality.', sort_order: 55 },
  { id: 'dc-gcse-psolve-0056', deck_id: 'deck-gcse-problem-solving', front: 'How to solve an equation involving algebraic fractions.', back: '1. Find the LCD of all denominators.\n2. Multiply every term by the LCD.\n3. Simplify and solve.\nExample: 3/(x+1) = 2/(x−1). LCD=(x+1)(x−1).\n3(x−1) = 2(x+1) → 3x−3 = 2x+2 → x = 5.\n\nGCSE Tip: Always check the solution doesn\'t make a denominator zero.', sort_order: 56 },
  { id: 'dc-gcse-psolve-0057', deck_id: 'deck-gcse-problem-solving', front: 'How to find the gradient of a curve at a point.', back: 'Differentiate to find dy/dx. Substitute the x-value of the point.\nExample: y = 3x²−5x. dy/dx = 6x−5. At x=2: gradient = 12−5 = 7.\n\nGCSE Tip: The gradient at a point on a curve is the gradient of the tangent at that point.', sort_order: 57 },
  { id: 'dc-gcse-psolve-0058', deck_id: 'deck-gcse-problem-solving', front: 'How to find where a curve has a horizontal tangent (stationary point).', back: 'Set dy/dx = 0 and solve for x.\nExample: y=x³−3x²+1. dy/dx=3x²−6x=3x(x−2)=0 → x=0 or x=2.\n\nGCSE Tip: Horizontal tangent = stationary point = local max or min. Then classify using second derivative.', sort_order: 58 },
  { id: 'dc-gcse-psolve-0059', deck_id: 'deck-gcse-problem-solving', front: 'Trick: how to solve "I think of a number" problems with algebra.', back: '"I think of a number, double it, add 7, and get 19." → 2x+7=19 → x=6.\n"I think of a number, square it, and the answer is 4 more than 3 times the number." → x²=3x+4 → x²−3x−4=0.\n\nGCSE Tip: Translate each operation into algebra. "Result is..." → equals sign.', sort_order: 59 },
  { id: 'dc-gcse-psolve-0060', deck_id: 'deck-gcse-problem-solving', front: 'How to find the k value in a proportion relationship.', back: 'Substitute the given pair of values into the proportion equation and solve for k.\ny ∝ x² → y=kx². Given y=45, x=3: 45=9k → k=5.\nAlways find k first before answering the main question.\n\nGCSE Tip: k is constant — find it once and use it for all other calculations.', sort_order: 60 },
  { id: 'dc-gcse-psolve-0061', deck_id: 'deck-gcse-problem-solving', front: 'Strategy: how to approach a simultaneous equation where one is quadratic.', back: '1. Rearrange the linear equation for one variable (y = ... or x = ...).\n2. Substitute into the quadratic.\n3. Solve the resulting quadratic.\n4. Substitute back to find the other variable.\nGive BOTH pairs of solutions.\n\nGCSE Tip: You should get 2 pairs of (x,y) solutions when a line meets a curve.', sort_order: 61 },
  { id: 'dc-gcse-psolve-0062', deck_id: 'deck-gcse-problem-solving', front: 'How to use iteration to solve equations to a required accuracy.', back: '1. Rearrange to xₙ₊₁ = f(xₙ) form.\n2. Start with a given or estimated x₀.\n3. Repeatedly substitute until the answers agree to required decimal places.\n4. Show at least 4 iterations.\n\nGCSE Tip: Stop when consecutive iterations round to the same value at the required accuracy.', sort_order: 62 },
  { id: 'dc-gcse-psolve-0063', deck_id: 'deck-gcse-problem-solving', front: 'How to write a proof that an expression is always positive.', back: 'Method: complete the square and show the result is always ≥ some positive number.\nExample: x²+4x+7 = (x+2)²+3. Since (x+2)²≥0, the expression ≥ 3 > 0. Always positive.\n\nGCSE Tip: Completing the square is the key technique for proving "always positive/negative".', sort_order: 63 },
  { id: 'dc-gcse-psolve-0064', deck_id: 'deck-gcse-problem-solving', front: 'How to find the turning point of a quadratic from its completed square form.', back: 'y = (x−a)² + b → turning point is (a, b).\ny = (x+3)² − 5 → turning point is (−3, −5).\n\nGCSE Tip: Watch signs carefully. (x−a)² → x=+a. (x+a)² → x=−a. The b value is the minimum (or max if negative x²).', sort_order: 64 },
  { id: 'dc-gcse-psolve-0065', deck_id: 'deck-gcse-problem-solving', front: 'How to read off transformation information from a graph equation.', back: 'y = af(x+b)+c\na → vertical stretch (or reflection if a<0)\nb → horizontal translation (opposite direction: +b → left)\nc → vertical translation (+c → up)\n\nGCSE Tip: Build transformations one step at a time. Apply horizontal changes before vertical.', sort_order: 65 },

  // GEOMETRY TRICKS (66-95)
  { id: 'dc-gcse-psolve-0066', deck_id: 'deck-gcse-problem-solving', front: 'First strategy for any geometry problem: draw a clear diagram.', back: 'Label all known lengths, angles and right angles. Mark unknown quantities with letters.\nDiagrams reveal which theorems apply and which formula to use.\n\nGCSE Tip: A well-labelled diagram is worth time spent. Examiners reward clear working.', sort_order: 66 },
  { id: 'dc-gcse-psolve-0067', deck_id: 'deck-gcse-problem-solving', front: 'How to identify which trig rule to use: SOH-CAH-TOA, sine rule or cosine rule.', back: 'Right-angled triangle → SOH-CAH-TOA.\nNon-right triangle, given 2 sides + included angle, or 3 sides → Cosine rule.\nNon-right triangle, given a side + opposite angle → Sine rule.\n\nGCSE Tip: Draw the triangle. Mark what you know. This decision tree becomes automatic with practice.', sort_order: 67 },
  { id: 'dc-gcse-psolve-0068', deck_id: 'deck-gcse-problem-solving', front: 'How to find missing angles in parallel line diagrams.', back: 'Label the parallel lines and transversal. Use:\n- Alternate angles (Z-angles): equal\n- Co-interior angles (C-angles): sum to 180°\n- Corresponding angles (F-angles): equal\n\nGCSE Tip: Always state which angle fact you\'re using. "Alternate angles are equal" earns method marks.', sort_order: 68 },
  { id: 'dc-gcse-psolve-0069', deck_id: 'deck-gcse-problem-solving', front: 'Trick to find the number of sides of a regular polygon from its interior angle.', back: 'Exterior angle = 180° − interior angle.\nNumber of sides = 360° ÷ exterior angle.\nExample: interior = 156° → exterior = 24° → sides = 360/24 = 15\n\nGCSE Tip: Exterior angle is the key. Sum of exterior angles is ALWAYS 360° for any polygon.', sort_order: 69 },
  { id: 'dc-gcse-psolve-0070', deck_id: 'deck-gcse-problem-solving', front: 'How to find the area of a composite shape.', back: '1. Split into simpler shapes (rectangles, triangles, circles, etc.).\n2. Calculate each area separately.\n3. Add (if included) or subtract (if cut out).\n\nGCSE Tip: For irregular composite shapes, look for rectangles first, then deal with the awkward bit.', sort_order: 70 },
  { id: 'dc-gcse-psolve-0071', deck_id: 'deck-gcse-problem-solving', front: 'How to find the area of a triangle when you don\'t know the height.', back: 'Use: Area = (1/2)ab sin C, where a and b are two sides and C is the included angle.\nExample: sides 7 and 9, included angle 50°.\nArea = (1/2)(7)(9)sin50° = 31.5 × 0.766 ≈ 24.1 cm²\n\nGCSE Tip: This formula works for ANY triangle. Essential when no perpendicular height is given.', sort_order: 71 },
  { id: 'dc-gcse-psolve-0072', deck_id: 'deck-gcse-problem-solving', front: 'How to find arc length and sector area quickly.', back: 'Both are a fraction of the full circle.\nFraction = angle/360\nArc length = (angle/360) × 2πr\nSector area = (angle/360) × πr²\n\nGCSE Tip: Think: "What fraction of the full circle is this sector?" Then multiply the full formula by that fraction.', sort_order: 72 },
  { id: 'dc-gcse-psolve-0073', deck_id: 'deck-gcse-problem-solving', front: 'How to find the area of a segment.', back: 'Area of segment = Area of sector − Area of triangle\n= (θ/360)πr² − (1/2)r²sinθ\n\nGCSE Tip: A segment is the region between a chord and the arc. Sector minus triangle.', sort_order: 73 },
  { id: 'dc-gcse-psolve-0074', deck_id: 'deck-gcse-problem-solving', front: 'Trick: spotting Pythagorean triples to avoid calculation.', back: 'Memorise: 3-4-5, 5-12-13, 8-15-17, 7-24-25\nAlso their multiples: 6-8-10, 9-12-15, 10-24-26\n\nExample: Triangle with legs 15 and 20 → divide by 5: 3-4-5 → hypotenuse = 25.\n\nGCSE Tip: Spotting Pythagorean triples saves time. Always look for multiples of these.', sort_order: 74 },
  { id: 'dc-gcse-psolve-0075', deck_id: 'deck-gcse-problem-solving', front: 'How to use 3D Pythagoras to find a space diagonal.', back: 'For a cuboid l×w×h: diagonal = √(l²+w²+h²)\nAlternatively: find diagonal of base first, then use that with the height.\nExample: 3×4×12 → base diag = 5, space diag = √(25+144) = √169 = 13\n\nGCSE Tip: Apply Pythagoras twice, or use the 3D formula directly.', sort_order: 75 },
  { id: 'dc-gcse-psolve-0076', deck_id: 'deck-gcse-problem-solving', front: 'How to find the angle between a line and a plane in 3D.', back: '1. Identify the foot of the perpendicular from the point to the plane.\n2. Draw the right triangle formed.\n3. Use tan, sin or cos as appropriate.\n\nExample: Diagonal of a box makes an angle θ with the base. tan θ = height/base diagonal.\n\nGCSE Tip: Always reduce 3D trigonometry to a 2D right triangle.', sort_order: 76 },
  { id: 'dc-gcse-psolve-0077', deck_id: 'deck-gcse-problem-solving', front: 'How to spot and use circle theorems efficiently.', back: 'Checklist:\n1. Angle at centre = 2× angle at circumference.\n2. Angle in semicircle = 90°.\n3. Angles in same segment are equal.\n4. Opposite angles in cyclic quadrilateral = 180°.\n5. Tangent ⊥ radius.\n6. Alternate segment theorem.\n\nGCSE Tip: Label all radii equal. Mark the centre clearly.', sort_order: 77 },
  { id: 'dc-gcse-psolve-0078', deck_id: 'deck-gcse-problem-solving', front: 'How to find the area of a regular polygon.', back: 'Split into n equal triangles from the centre.\nArea of each triangle = (1/2)r²sin(360°/n)\nTotal area = n × (1/2)r²sin(360°/n)\n\nGCSE Tip: Alternatively use area = (1/2)×perimeter×apothem for regular polygons.', sort_order: 78 },
  { id: 'dc-gcse-psolve-0079', deck_id: 'deck-gcse-problem-solving', front: 'How to find the bearing of one point from another.', back: 'Bearings are measured CLOCKWISE from NORTH.\nAlways written as 3 digits (e.g. 045°, not 45°).\nTo find back-bearing: add 180° (subtract 180° if result ≥ 360°).\n\nGCSE Tip: Always draw a North arrow at the starting point. Bearings start from North and go clockwise.', sort_order: 79 },
  { id: 'dc-gcse-psolve-0080', deck_id: 'deck-gcse-problem-solving', front: 'How to approach a locus problem.', back: 'A locus is the set of all points satisfying a condition.\n- Equal distance from a point → circle\n- Equal distance from a line → parallel line (or pair of parallel lines)\n- Equal distance from two points → perpendicular bisector\n- Equal distance from two lines → angle bisector\n\nGCSE Tip: Sketch the locus type first, then apply the given measurements.', sort_order: 80 },
  { id: 'dc-gcse-psolve-0081', deck_id: 'deck-gcse-problem-solving', front: 'How to construct the perpendicular bisector accurately.', back: '1. Set compass to more than half the line length.\n2. Draw arcs above and below the line from each endpoint.\n3. Connect the two arc intersections.\n\nGCSE Tip: Don\'t change the compass width between the two arc sets. Leave construction arcs visible.', sort_order: 81 },
  { id: 'dc-gcse-psolve-0082', deck_id: 'deck-gcse-problem-solving', front: 'How to fully describe a transformation.', back: 'Reflection: mirror line equation.\nRotation: centre, angle, direction (CW or CCW).\nTranslation: column vector.\nEnlargement: centre, scale factor (+ sign if same orientation, − if inverted).\n\nGCSE Tip: "Fully describe" means ALL required details. Missing one detail = mark lost.', sort_order: 82 },
  { id: 'dc-gcse-psolve-0083', deck_id: 'deck-gcse-problem-solving', front: 'How to find the centre of rotation.', back: '1. Draw a line connecting a point to its image.\n2. Construct the perpendicular bisector of this line.\n3. Repeat for another point and its image.\n4. The centre is the intersection of the perpendicular bisectors.\n\nGCSE Tip: Use tracing paper to check by trial and error first.', sort_order: 83 },
  { id: 'dc-gcse-psolve-0084', deck_id: 'deck-gcse-problem-solving', front: 'How to find the scale factor of an enlargement from a diagram.', back: 'SF = image length ÷ object length\nFor a negative SF: check if the image is on the opposite side of the centre.\nExample: Object edge 4cm, image edge 10cm → SF = 2.5\n\nGCSE Tip: Always measure corresponding sides. Negative SF → image inverted and on opposite side.', sort_order: 84 },
  { id: 'dc-gcse-psolve-0085', deck_id: 'deck-gcse-problem-solving', front: 'How to use similar triangles to find missing lengths.', back: '1. Identify that the triangles are similar (AAA, SAS, SSS).\n2. Find the scale factor from a known pair of corresponding sides.\n3. Multiply or divide the unknown side by the scale factor.\n\nGCSE Tip: Mark equal angles clearly. Write the ratio of corresponding sides as a fraction.', sort_order: 85 },
  { id: 'dc-gcse-psolve-0086', deck_id: 'deck-gcse-problem-solving', front: 'How to find surface area of complex 3D solids.', back: '1. Identify each face (flat or curved).\n2. Calculate area of each face separately.\n3. Sum all face areas.\n\nWatch for: shared faces that should NOT be included (e.g. base of cone sitting on cylinder).\n\nGCSE Tip: Draw a "net" mentally or on paper. Count every visible face.', sort_order: 86 },
  { id: 'dc-gcse-psolve-0087', deck_id: 'deck-gcse-problem-solving', front: 'How to find the volume of a prism.', back: 'Volume = Area of cross-section × Length\n\nWorks for any prism (triangular, hexagonal, L-shaped, etc.)\nExample: L-shaped cross-section area = 20cm², length 8cm → Volume = 160cm³\n\nGCSE Tip: Identify the consistent cross-section first. Volume = cross-section area × depth.', sort_order: 87 },
  { id: 'dc-gcse-psolve-0088', deck_id: 'deck-gcse-problem-solving', front: 'How to find the volume of a frustum (truncated cone).', back: 'Volume of frustum = Volume of full cone − Volume of removed small cone.\n\nUse similar triangles to find the dimensions of the small cone.\n\nGCSE Tip: A frustum is a cone with its top cut off. Work out the full cone first.', sort_order: 88 },
  { id: 'dc-gcse-psolve-0089', deck_id: 'deck-gcse-problem-solving', front: 'How to use angle of elevation and depression in trigonometry.', back: 'Angle of elevation: angle UP from horizontal to the object.\nAngle of depression: angle DOWN from horizontal to the object.\nBoth form right triangles with horizontal ground.\ntanθ = height/horizontal distance\n\nGCSE Tip: Draw a horizontal line first. Label the angle clearly. The right angle is at the base.', sort_order: 89 },
  { id: 'dc-gcse-psolve-0090', deck_id: 'deck-gcse-problem-solving', front: 'Strategy: how to solve a two-triangle trig problem.', back: 'Problems with two connected triangles often involve finding a shared side or angle.\n1. Find all you can in the first triangle.\n2. Use that result in the second triangle.\n\nGCSE Tip: Label every known value after each step. Show all intermediate answers.', sort_order: 90 },
  { id: 'dc-gcse-psolve-0091', deck_id: 'deck-gcse-problem-solving', front: 'How to find the exact height or area using special triangle angles (30-60-90 or 45-45-90).', back: '30-60-90: sides in ratio 1 : √3 : 2\n45-45-90: sides in ratio 1 : 1 : √2\nUse these to avoid a calculator and give exact answers.\n\nExample: equilateral triangle, side 6: height = 6×(√3/2) = 3√3\n\nGCSE Tip: Memorise these ratios — they appear frequently on non-calculator papers.', sort_order: 91 },
  { id: 'dc-gcse-psolve-0092', deck_id: 'deck-gcse-problem-solving', front: 'How to use the sine rule when given two angles and a side.', back: 'Find the third angle first (angle sum = 180°).\nThen: a/sinA = b/sinB = c/sinC\nUse the pair where you have both: known side/sin(known angle) = unknown side/sin(unknown angle)\n\nGCSE Tip: You always need a matched side-angle pair to use the sine rule.', sort_order: 92 },
  { id: 'dc-gcse-psolve-0093', deck_id: 'deck-gcse-problem-solving', front: 'How to handle ambiguous case in sine rule (two possible triangles).', back: 'When given two sides and a non-included angle (SSA), there may be TWO possible triangles.\nIf sin A < 1 and the given angle is acute and the given side is shorter than the other, check both:\nAngle = θ or angle = 180°−θ\n\nGCSE Tip: Draw a sketch to see if two triangles are possible. Mention both solutions if they exist.', sort_order: 93 },
  { id: 'dc-gcse-psolve-0094', deck_id: 'deck-gcse-problem-solving', front: 'How to convert between degrees and radians (if needed for higher content).', back: '180° = π radians\nTo convert degrees to radians: × π/180\nTo convert radians to degrees: × 180/π\nExamples: 90° = π/2 rad; π/6 = 30°\n\nGCSE Tip: At GCSE level, most trig is in degrees. Radians appear more in A-Level content.', sort_order: 94 },
  { id: 'dc-gcse-psolve-0095', deck_id: 'deck-gcse-problem-solving', front: 'How to find a missing side using the cosine rule efficiently.', back: 'a² = b² + c² − 2bc cos A\n1. Identify A (the angle) and b, c (the sides enclosing A).\n2. Calculate each part separately.\n3. Take the square root at the end.\n\nGCSE Tip: Keep the full value in your calculator. Only round at the final step.', sort_order: 95 },

  // RATIO, PROPORTION & RATES (96-115)
  { id: 'dc-gcse-psolve-0096', deck_id: 'deck-gcse-problem-solving', front: 'How to split a quantity in a three-part ratio.', back: '1. Add all ratio parts.\n2. Divide the total by the sum to find one part.\n3. Multiply by each ratio number.\nExample: £630 in ratio 2:3:7. Sum=12. One part=£52.50. Shares: £105, £157.50, £367.50.\n\nGCSE Tip: Always check shares sum to the original total.', sort_order: 96 },
  { id: 'dc-gcse-psolve-0097', deck_id: 'deck-gcse-problem-solving', front: 'How to combine two separate ratios into one.', back: 'Find a common value for the shared quantity.\nExample: a:b=2:3, b:c=4:5. Make b the same: a:b=8:12, b:c=12:15. So a:b:c=8:12:15.\n\nGCSE Tip: Scale both ratios so the shared quantity has the same value (LCM of the b values).', sort_order: 97 },
  { id: 'dc-gcse-psolve-0098', deck_id: 'deck-gcse-problem-solving', front: 'How to solve a "difference in ratio" problem.', back: 'If the difference between two shares is given, find the value of one part.\nExample: A:B = 3:7. A gets £60 less than B. Difference = 4 parts = £60. One part = £15.\nA = 3×15 = £45, B = 7×15 = £105.\n\nGCSE Tip: Difference in ratio numbers × one part = actual difference.', sort_order: 98 },
  { id: 'dc-gcse-psolve-0099', deck_id: 'deck-gcse-problem-solving', front: 'How to interpret a real-world proportionality graph.', back: 'Straight line through origin → direct proportion (y = kx).\nCurved upward through origin → y ∝ xⁿ (n>1).\nDecreasing curve through axes → inverse proportion.\n\nGCSE Tip: The shape of the graph tells you the type of relationship. State "directly proportional" when you see y=kx.', sort_order: 99 },
  { id: 'dc-gcse-psolve-0100', deck_id: 'deck-gcse-problem-solving', front: 'How to convert a map scale to find a real-life area.', back: 'Scale 1:n → lengths scale by n.\nArea scales by n².\nExample: Scale 1:50000. 4cm² on map → real area = 4 × 50000² cm² = 4 × 2.5×10⁹ cm² = 10km²\n\nGCSE Tip: Convert units carefully: cm² to m² (÷10000) to km² (÷10⁶).', sort_order: 100 },
  { id: 'dc-gcse-psolve-0101', deck_id: 'deck-gcse-problem-solving', front: 'How to solve "worker" problems (more workers = less time).', back: 'Total work = workers × time = constant.\nExample: 4 workers take 9 days. 6 workers take: 4×9=36 worker-days. 36÷6=6 days.\n\nGCSE Tip: Find the total "worker-days" first. This is the key to inverse proportion worker problems.', sort_order: 101 },
  { id: 'dc-gcse-psolve-0102', deck_id: 'deck-gcse-problem-solving', front: 'How to find average speed for a two-leg journey.', back: 'Average speed ≠ arithmetic mean of speeds.\nAverage speed = total distance ÷ total time.\nExample: 60mph for 2hrs + 40mph for 3hrs → total dist=120+120=240mi, total time=5hrs. Avg = 48mph.\n\nGCSE Tip: Never average the speeds directly unless the times are equal.', sort_order: 102 },
  { id: 'dc-gcse-psolve-0103', deck_id: 'deck-gcse-problem-solving', front: 'How to read a distance-time graph.', back: 'Gradient = speed. Steeper gradient = faster.\nHorizontal line = stationary.\nNegative gradient = returning towards start.\n\nGCSE Tip: Gradient = Δy/Δx = distance/time = speed. Use two widely spaced points for accuracy.', sort_order: 103 },
  { id: 'dc-gcse-psolve-0104', deck_id: 'deck-gcse-problem-solving', front: 'How to interpret a velocity-time graph.', back: 'Gradient = acceleration (m/s²).\nArea under graph = distance travelled.\nHorizontal = constant velocity. Upward = accelerating. Downward = decelerating.\n\nGCSE Tip: Count squares or use triangle/trapezium formula for the area.', sort_order: 104 },
  { id: 'dc-gcse-psolve-0105', deck_id: 'deck-gcse-problem-solving', front: 'How to solve a "pipes filling a tank" rate problem.', back: 'Find each pipe\'s rate (fraction of tank per hour). Add rates.\nExample: Pipe A fills in 4hrs (rate=1/4), Pipe B in 6hrs (rate=1/6).\nCombined rate = 1/4+1/6 = 3/12+2/12 = 5/12 per hour. Time = 12/5 = 2.4 hrs.\n\nGCSE Tip: Combined rate = sum of individual rates. Time = 1/combined rate.', sort_order: 105 },
  { id: 'dc-gcse-psolve-0106', deck_id: 'deck-gcse-problem-solving', front: 'How to convert units of area (e.g. cm² to m²).', back: '1 m = 100 cm → 1 m² = 100² = 10000 cm²\nSo to convert cm² to m²: ÷ 10000\nExample: 45000 cm² = 45000÷10000 = 4.5 m²\n\nGCSE Tip: Square the unit conversion factor. 1m=100cm but 1m²=10000cm² (not 100cm²).', sort_order: 106 },
  { id: 'dc-gcse-psolve-0107', deck_id: 'deck-gcse-problem-solving', front: 'How to convert units of volume (e.g. cm³ to litres).', back: '1 litre = 1000 cm³\n1 m³ = 1,000,000 cm³\nExample: 2500 cm³ = 2.5 litres\nExample: 0.003 m³ = 3000 cm³ = 3 litres\n\nGCSE Tip: 1 litre = 1000 cm³ = 1 dm³. 1 m³ = 1000 litres.', sort_order: 107 },
  { id: 'dc-gcse-psolve-0108', deck_id: 'deck-gcse-problem-solving', front: 'How to handle exchange rate problems.', back: 'Identify the direction: are you converting TO or FROM the foreign currency?\nIf £1 = 1.15 euros: £50 → euros: 50 × 1.15 = 57.50 euros\n€80 → pounds: 80 ÷ 1.15 = £69.57\n\nGCSE Tip: × to get more units, ÷ to get fewer. Check using common sense.', sort_order: 108 },
  { id: 'dc-gcse-psolve-0109', deck_id: 'deck-gcse-problem-solving', front: 'How to find the gradient of a real-life graph (e.g. depth-time graph).', back: 'Gradient = rise ÷ run = change in y ÷ change in x\nAlways include units in the answer.\nExample: depth increases 20cm in 5s → gradient = 4 cm/s (rate of fill)\n\nGCSE Tip: The units of the gradient tell you what it represents physically.', sort_order: 109 },
  { id: 'dc-gcse-psolve-0110', deck_id: 'deck-gcse-problem-solving', front: 'How to solve a mixture/concentration problem.', back: 'Use: amount of substance = concentration × volume.\nExample: Mix 300ml of 40% juice and 200ml of 20% juice.\nTotal juice = 300×0.4 + 200×0.2 = 120 + 40 = 160ml in 500ml. Concentration = 160/500 = 32%.\n\nGCSE Tip: Find the total amount of the substance, then divide by total volume.', sort_order: 110 },
  { id: 'dc-gcse-psolve-0111', deck_id: 'deck-gcse-problem-solving', front: 'How to approach a "growth and decay" real-life problem.', back: 'Exponential growth: amount = initial × (1+r)ⁿ\nExponential decay: amount = initial × (1−r)ⁿ\nPopulation, compound interest, radioactive decay, depreciation all follow this pattern.\n\nGCSE Tip: Identify whether it\'s growth or decay. Write the multiplier. Raise to the power of time periods.', sort_order: 111 },
  { id: 'dc-gcse-psolve-0112', deck_id: 'deck-gcse-problem-solving', front: 'How to find the percentage profit or loss.', back: '% profit = (profit / cost price) × 100\nProfit = selling price − cost price\nExample: Bought for £40, sold for £52. Profit = £12. % profit = (12/40)×100 = 30%\n\nGCSE Tip: Always divide by the ORIGINAL (cost) price, not the selling price.', sort_order: 112 },
  { id: 'dc-gcse-psolve-0113', deck_id: 'deck-gcse-problem-solving', front: 'How to find the original quantity given a percentage of it.', back: '"30% of a number is 45. Find the number."\n0.3 × x = 45 → x = 45/0.3 = 150\nOr: 1% = 45/30 = 1.5; 100% = 150\n\nGCSE Tip: If given a % and the result, divide the result by the decimal form of the percentage.', sort_order: 113 },
  { id: 'dc-gcse-psolve-0114', deck_id: 'deck-gcse-problem-solving', front: 'How to tackle a "sharing in ratio with a condition" problem.', back: 'Example: "B gets £20 more than A. They share in ratio 3:5. Find each share."\nDifference = 5−3 = 2 parts = £20 → 1 part = £10\nA = 3×£10 = £30, B = 5×£10 = £50\nCheck: difference = £20 ✓\n\nGCSE Tip: The given difference maps to the difference in ratio parts.', sort_order: 114 },
  { id: 'dc-gcse-psolve-0115', deck_id: 'deck-gcse-problem-solving', front: 'How to handle a density/mass/volume problem.', back: 'D = M/V (Density = Mass ÷ Volume)\nTriangle: cover the unknown. M=D×V, V=M/D\nExample: Density 8 g/cm³, volume 25 cm³ → mass = 8×25 = 200g\n\nGCSE Tip: Same triangle method works for speed (D=S×T) and pressure (P=F/A).', sort_order: 115 },

  // STATISTICS & PROBABILITY TRICKS (116-135)
  { id: 'dc-gcse-psolve-0116', deck_id: 'deck-gcse-problem-solving', front: 'How to decide which average to calculate.', back: 'Mean: most commonly required. Use when data is numerical and there are no extreme outliers.\nMedian: use when there are outliers or skewed data.\nMode: use for categorical data or when asked "most common".\n\nGCSE Tip: If not specified, calculate mean. If outliers are mentioned, consider median.', sort_order: 116 },
  { id: 'dc-gcse-psolve-0117', deck_id: 'deck-gcse-problem-solving', front: 'How to use a cumulative frequency graph to find quartiles.', back: 'For n data points:\nQ1 at n/4, Q2 (median) at n/2, Q3 at 3n/4.\nDraw horizontal lines from these values to the curve, then drop vertically to find the data values.\n\nGCSE Tip: IQR = Q3−Q1. Box plot uses min, Q1, Q2, Q3, max.', sort_order: 117 },
  { id: 'dc-gcse-psolve-0118', deck_id: 'deck-gcse-problem-solving', front: 'How to read a histogram correctly.', back: 'Frequency = area of bar (not height!).\nFrequency = height × class width (where height = frequency density).\nTo compare bars: calculate areas, not heights.\n\nGCSE Tip: In histograms with unequal class widths, the height (frequency density) can be misleading.', sort_order: 118 },
  { id: 'dc-gcse-psolve-0119', deck_id: 'deck-gcse-problem-solving', front: 'How to draw a box plot from data.', back: '1. Find min, Q1, median, Q3, max.\n2. Draw a scale.\n3. Draw a box from Q1 to Q3.\n4. Mark median inside box.\n5. Draw whiskers from Q1 to min and Q3 to max.\n\nGCSE Tip: The box represents the middle 50% of data. Whiskers show the full range.', sort_order: 119 },
  { id: 'dc-gcse-psolve-0120', deck_id: 'deck-gcse-problem-solving', front: 'How to compare two data sets using box plots.', back: 'Compare: 1. Medians (typical value). 2. IQR (spread). 3. Range. 4. Shape/skew.\nAlways give values from the graphs AND a comparison word (higher, wider, etc.)\n\nGCSE Tip: "Compare" requires you to make a comparative statement, not just state two separate facts.', sort_order: 120 },
  { id: 'dc-gcse-psolve-0121', deck_id: 'deck-gcse-problem-solving', front: 'Strategy: how to draw a tree diagram for a two-stage probability problem.', back: '1. First event branches on the left.\n2. Second event branches from each first-event outcome.\n3. Label each branch with its probability.\n4. Check: branches from each node sum to 1.\n5. Multiply along branches for "and", add across branches for "or".\n\nGCSE Tip: Always verify branch probabilities sum to 1 at each node.', sort_order: 121 },
  { id: 'dc-gcse-psolve-0122', deck_id: 'deck-gcse-problem-solving', front: 'How to find P(at least one) efficiently.', back: 'P(at least one) = 1 − P(none)\nMuch easier than adding all cases (1, 2, 3, ...).\nExample: P(at least one head in 4 flips) = 1 − P(all tails) = 1 − (1/2)⁴ = 1 − 1/16 = 15/16\n\nGCSE Tip: Complementary rule is the key strategy for "at least one" problems.', sort_order: 122 },
  { id: 'dc-gcse-psolve-0123', deck_id: 'deck-gcse-problem-solving', front: 'How to use a Venn diagram to solve probability problems.', back: '1. Label regions: A only, B only, A∩B, neither.\n2. Fill in values from the given information.\n3. Use total to find unknown regions.\n4. P(event) = frequency in region ÷ total.\n\nGCSE Tip: Start with the intersection (A∩B) and work outwards. Total must equal the sum of all regions.', sort_order: 123 },
  { id: 'dc-gcse-psolve-0124', deck_id: 'deck-gcse-problem-solving', front: 'How to solve a conditional probability problem.', back: 'P(B|A) = P(A and B) / P(A)\n"Given A has occurred, find P(B)." Restrict your sample space to A.\nExample: P(A∩B)=0.3, P(A)=0.5 → P(B|A) = 0.3/0.5 = 0.6\n\nGCSE Tip: Conditional probability narrows the sample space. Think: "out of those with A, how many also have B?"', sort_order: 124 },
  { id: 'dc-gcse-psolve-0125', deck_id: 'deck-gcse-problem-solving', front: 'How to check if two events are independent.', back: 'A and B are independent if P(A∩B) = P(A) × P(B).\nIf this holds → independent. If not → dependent.\nExample: P(A)=0.4, P(B)=0.5, P(A∩B)=0.2. 0.4×0.5=0.2 ✓ → independent.\n\nGCSE Tip: Also check P(B|A) = P(B). If yes, knowing A happened doesn\'t affect B.', sort_order: 125 },
  { id: 'dc-gcse-psolve-0126', deck_id: 'deck-gcse-problem-solving', front: 'How to calculate expected frequency.', back: 'Expected frequency = probability × number of trials.\nExample: P(6 on die) = 1/6. In 300 rolls, expected number of sixes = 300 × 1/6 = 50.\n\nGCSE Tip: Expected frequency tells you what to EXPECT, not what will definitely happen.', sort_order: 126 },
  { id: 'dc-gcse-psolve-0127', deck_id: 'deck-gcse-problem-solving', front: 'How to estimate probability from experimental data (relative frequency).', back: 'Relative frequency = number of times event occurred ÷ total trials.\nMore trials → relative frequency → theoretical probability.\nExample: 60 heads in 200 flips → P(head) ≈ 60/200 = 0.3 (biased coin).\n\nGCSE Tip: As n → ∞, relative frequency approaches the true probability.', sort_order: 127 },
  { id: 'dc-gcse-psolve-0128', deck_id: 'deck-gcse-problem-solving', front: 'How to use a two-way table for probability.', back: 'Read off the required cell count, then divide by the total (or row/column total for conditional).\nExample: 60 students, 35 male, 25 female; 20 male like sport. P(sport|male) = 20/35 = 4/7.\n\nGCSE Tip: Conditional probability from a table: restrict to the given row or column.', sort_order: 128 },
  { id: 'dc-gcse-psolve-0129', deck_id: 'deck-gcse-problem-solving', front: 'How to complete a frequency tree.', back: '1. Start with the total.\n2. Split by first category; the branches sum to the total.\n3. Split each branch by the second category; sub-branches sum to their parent.\n4. Work from known values to fill unknowns.\n\nGCSE Tip: Every level must sum correctly. Use subtraction to find missing values.', sort_order: 129 },
  { id: 'dc-gcse-psolve-0130', deck_id: 'deck-gcse-problem-solving', front: 'How to set up equations from probability problems.', back: 'Example: A bag has x red and (x+3) blue balls. P(red) = 1/4.\nx/(x + x+3) = 1/4 → x/(2x+3) = 1/4 → 4x = 2x+3 → x=1.5 ...\n\nGCSE Tip: Write P(event) = favourable/total, set equal to the given probability, and solve algebraically.', sort_order: 130 },
  { id: 'dc-gcse-psolve-0131', deck_id: 'deck-gcse-problem-solving', front: 'How to approach a stratified sampling question.', back: '1. Find the proportion each group represents.\n2. Multiply by the sample size.\nExample: 300 Year 10, 500 Year 11, total 800. Sample 40.\nYear 10: (300/800)×40=15. Year 11: (500/800)×40=25.\n\nGCSE Tip: Round sensibly so the samples sum to the required total.', sort_order: 131 },
  { id: 'dc-gcse-psolve-0132', deck_id: 'deck-gcse-problem-solving', front: 'How to calculate the mean from a grouped frequency table.', back: '1. Find midpoint of each class.\n2. Multiply midpoint × frequency for each class.\n3. Sum all fx values.\n4. Divide by total frequency.\nMean = Σfx/Σf\n\nGCSE Tip: This is an ESTIMATE of the mean — exact values are unknown in grouped data.', sort_order: 132 },
  { id: 'dc-gcse-psolve-0133', deck_id: 'deck-gcse-problem-solving', front: 'How to describe skewness from a box plot or frequency diagram.', back: 'Positive skew: longer tail to the right; mean > median > mode.\nNegative skew: longer tail to the left; mean < median < mode.\nSymmetric: approximately equal tails; mean ≈ median ≈ mode.\n\nGCSE Tip: In a box plot: if median is closer to Q1 → positive skew. Closer to Q3 → negative skew.', sort_order: 133 },
  { id: 'dc-gcse-psolve-0134', deck_id: 'deck-gcse-problem-solving', front: 'How to draw and interpret a scatter diagram.', back: '1. Plot each (x,y) pair as a point.\n2. Observe direction and spread: positive/negative/no correlation.\n3. Draw a line of best fit through the "middle" of the points.\n4. Use the line to predict values.\n\nGCSE Tip: The line of best fit should have roughly equal points above and below it. It may not pass through any data point.', sort_order: 134 },
  { id: 'dc-gcse-psolve-0135', deck_id: 'deck-gcse-problem-solving', front: 'How to identify a misleading statistical diagram.', back: 'Common tricks: y-axis not starting at zero (exaggerates differences), inconsistent scales, 3D pie charts (distort areas), missing sample size information.\n\nGCSE Tip: Always check: Does the axis start at 0? Is the scale consistent? Is the sample size stated?', sort_order: 135 },

  // EXAM TECHNIQUE & STRATEGY (136-165)
  { id: 'dc-gcse-psolve-0136', deck_id: 'deck-gcse-problem-solving', front: 'How to use the mark allocation to guide your working.', back: '1 mark: usually a single fact or short answer.\n2 marks: method + answer.\n3+ marks: full method, calculation, and correct answer.\n\nGCSE Tip: Count the marks and show at least that many distinct steps. Don\'t skip steps on 3-mark questions.', sort_order: 136 },
  { id: 'dc-gcse-psolve-0137', deck_id: 'deck-gcse-problem-solving', front: 'How to gain method marks even when you get the wrong answer.', back: 'Show all working clearly. Examiners give method marks (M marks) for correct method even if the final answer is wrong.\nIf you make an arithmetic error, subsequent marks can still be awarded (follow-through marks).\n\nGCSE Tip: Never leave a question blank. A wrong answer with working can score more than a blank page.', sort_order: 137 },
  { id: 'dc-gcse-psolve-0138', deck_id: 'deck-gcse-problem-solving', front: 'How to deal with a question you\'re stuck on.', back: '1. Read the question again carefully — identify all given information.\n2. Write down any relevant formulae.\n3. Try a simpler case or draw a diagram.\n4. Move on and return later with fresh eyes.\n5. Write down partial working — you may earn method marks.\n\nGCSE Tip: Never spend too long on one question. Flag and return.', sort_order: 138 },
  { id: 'dc-gcse-psolve-0139', deck_id: 'deck-gcse-problem-solving', front: 'How to round correctly based on the question\'s instruction.', back: 'Decimal places: count digits after the decimal point.\nSignificant figures: count from the first non-zero digit.\n"To the nearest 100": 3450 → 3500.\n\nGCSE Tip: Don\'t round intermediate values. Only round the final answer to the required accuracy.', sort_order: 139 },
  { id: 'dc-gcse-psolve-0140', deck_id: 'deck-gcse-problem-solving', front: 'How to avoid losing marks on "explain" or "justify" questions.', back: '"Explain" needs a reason, not just a number. Reference the maths.\n"This is a translation because all points moved by the same vector (3, −2)." ✓\n"It moved." ✗\n\nGCSE Tip: Tie your explanation to a mathematical property. Use vocabulary: translation, gradient, similar, etc.', sort_order: 140 },
  { id: 'dc-gcse-psolve-0141', deck_id: 'deck-gcse-problem-solving', front: 'How to check your answer to an equation.', back: 'Substitute your solution back into the ORIGINAL equation and verify both sides are equal.\nExample: x=3 for 4x−3=9: LHS=12−3=9=RHS ✓\n\nGCSE Tip: If LHS ≠ RHS, you have made an error. Don\'t check in a rearranged form — use the original.', sort_order: 141 },
  { id: 'dc-gcse-psolve-0142', deck_id: 'deck-gcse-problem-solving', front: 'How to interpret "not drawn accurately" diagrams.', back: 'When a diagram says "not drawn accurately" (NDA), you CANNOT measure from it.\nYou must calculate using the given values and appropriate formulae/theorems.\n\nGCSE Tip: NDA diagrams are just guides for setting up the problem. Work algebraically.', sort_order: 142 },
  { id: 'dc-gcse-psolve-0143', deck_id: 'deck-gcse-problem-solving', front: 'How to structure a proof question.', back: '1. Define variables with general forms (e.g. 2n for even, 2n+1 for odd).\n2. Perform the algebraic manipulation.\n3. Show the result has the required property (divisible by k, always positive, etc.).\n4. Write a concluding statement.\n\nGCSE Tip: Start with definitions, end with a clear conclusion. Proofs must be watertight with no assumed steps.', sort_order: 143 },
  { id: 'dc-gcse-psolve-0144', deck_id: 'deck-gcse-problem-solving', front: 'How to avoid the "losing the negative" error in algebra.', back: 'Watch for: expanding −2(x−3) = −2x+6 (not −2x−6).\nAnd: subtracting a bracket: 5 − (3x−2) = 5−3x+2 = 7−3x (not 5−3x−2).\n\nGCSE Tip: When a negative sign precedes a bracket, every term inside changes sign. Write it out carefully.', sort_order: 144 },
  { id: 'dc-gcse-psolve-0145', deck_id: 'deck-gcse-problem-solving', front: 'How to identify what type of question it is from key vocabulary.', back: '"Find/Calculate": numerical answer required.\n"Show/Prove": demonstration with full working.\n"Explain/State/Describe": words needed, not just numbers.\n"Sketch": rough shape, key points labelled.\n"Draw": accurate plot/construction.\n\nGCSE Tip: Read the command word carefully — it tells you exactly what form the answer should take.', sort_order: 145 },
  { id: 'dc-gcse-psolve-0146', deck_id: 'deck-gcse-problem-solving', front: 'How to tackle a multi-step problem without getting lost.', back: '1. Identify what the question is ultimately asking for.\n2. Work backwards: what do I need to find that?\n3. Identify what you know.\n4. Build a chain: known → intermediate result → final answer.\n\nGCSE Tip: Write down each step clearly. Label intermediate answers. Show all units.', sort_order: 146 },
  { id: 'dc-gcse-psolve-0147', deck_id: 'deck-gcse-problem-solving', front: 'How to handle a question with multiple parts that build on each other.', back: 'If you can\'t answer part (a), make up a sensible value and use it in part (b). State what you\'re doing: "Using x=10 from (a)...".\n\nGCSE Tip: Marks in later parts often require the method only, not the specific number from earlier. Don\'t give up.', sort_order: 147 },
  { id: 'dc-gcse-psolve-0148', deck_id: 'deck-gcse-problem-solving', front: 'How to check units throughout a multi-step calculation.', back: 'Keep units in every line of working:\n50 km ÷ 1.25 hours = 40 km/h\n\nConversion errors are common: check cm vs m vs km, cm² vs m², g vs kg.\n\nGCSE Tip: If the units of your answer don\'t match what\'s asked, you\'ve made a conversion error.', sort_order: 148 },
  { id: 'dc-gcse-psolve-0149', deck_id: 'deck-gcse-problem-solving', front: 'How to write your final answer to a "give your answer correct to..." question.', back: 'Round only the final answer, not intermediate steps.\nWrite "= 4.7" (to 1 d.p.) or "= 4.65" (to 3 s.f.) clearly.\nIf the answer is exact (e.g. 4.5), you still write 4.5 — no rounding needed.\n\nGCSE Tip: Keep full calculator precision throughout; truncate only at the very end.', sort_order: 149 },
  { id: 'dc-gcse-psolve-0150', deck_id: 'deck-gcse-problem-solving', front: 'How to gain marks on a "compare" question in statistics.', back: 'A complete comparison must:\n1. Compare a measure of average (e.g. "Group A has a higher median of 65 vs 58").\n2. Compare a measure of spread (e.g. "Group A is more consistent — IQR 12 vs 18").\n3. Use the context of the question.\n\nGCSE Tip: Always quote values from the graph. A comparison needs two values and a judgement.', sort_order: 150 },

  // HIGHER TIER TRICKS (151-200)
  { id: 'dc-gcse-psolve-0151', deck_id: 'deck-gcse-problem-solving', front: 'How to simplify a surd expression of the form (a+√b)(c+√d).', back: 'Expand using FOIL.\nExample: (2+√3)(1+√3) = 2 + 2√3 + √3 + (√3)² = 2 + 3√3 + 3 = 5 + 3√3\n\nGCSE Tip: (√a)² = a. Collect the integer and surd parts separately.', sort_order: 151 },
  { id: 'dc-gcse-psolve-0152', deck_id: 'deck-gcse-problem-solving', front: 'How to rationalise a denominator of the form 1/(a+√b).', back: 'Multiply top and bottom by the conjugate (a−√b).\nExample: 1/(2+√3) × (2−√3)/(2−√3) = (2−√3)/(4−3) = 2−√3\n\nGCSE Tip: Denominator becomes a²−b (difference of two squares). This eliminates the surd from the denominator.', sort_order: 152 },
  { id: 'dc-gcse-psolve-0153', deck_id: 'deck-gcse-problem-solving', front: 'How to use vectors to prove geometrical facts.', back: '1. Express all relevant vectors in terms of a and b.\n2. Show the required result (e.g. collinearity, parallel, midpoint).\nCollinear: one vector is a scalar multiple of another and they share a point.\nParallel: vectors are scalar multiples.\n\nGCSE Tip: Find vector paths by combining a and b. If two vectors are parallel and share a point → collinear.', sort_order: 153 },
  { id: 'dc-gcse-psolve-0154', deck_id: 'deck-gcse-problem-solving', front: 'How to use the discriminant to find an unknown constant.', back: 'If equal roots: b²−4ac = 0.\nIf two distinct roots: b²−4ac > 0.\nIf no real roots: b²−4ac < 0.\nSet up the discriminant with the unknown constant and solve.\nExample: x²+kx+4=0 has equal roots → k²−16=0 → k=±4\n\nGCSE Tip: Set up b²−4ac with the unknown, then solve the resulting equation.', sort_order: 154 },
  { id: 'dc-gcse-psolve-0155', deck_id: 'deck-gcse-problem-solving', front: 'How to find the inverse of a composite function.', back: '(gf)⁻¹ = f⁻¹g⁻¹ (reverse order!)\nAlternatively: let y=gf(x), express x in terms of y step by step.\nExample: f(x)=2x, g(x)=x+3. gf(x)=2x+3.\n(gf)⁻¹(x) = (x−3)/2\n\nGCSE Tip: Find the composite function first, then invert it. Or invert f and g individually and reverse the order.', sort_order: 155 },
  { id: 'dc-gcse-psolve-0156', deck_id: 'deck-gcse-problem-solving', front: 'How to prove two lines are perpendicular using gradients.', back: 'Two lines are perpendicular if m₁ × m₂ = −1.\nExample: Line 1 has gradient 3/4. Line 2 has gradient −4/3. Product = (3/4)(−4/3) = −1 ✓ Perpendicular.\n\nGCSE Tip: Check the product of gradients. If it equals −1, the lines are perpendicular.', sort_order: 156 },
  { id: 'dc-gcse-psolve-0157', deck_id: 'deck-gcse-problem-solving', front: 'How to find the equation of a tangent to a circle.', back: '1. Find the gradient of the radius (from centre to the point).\n2. Tangent gradient = negative reciprocal.\n3. Use y−y₁ = m(x−x₁) with the point of tangency.\n\nGCSE Tip: Radius ⊥ tangent is the key theorem. Always find radius gradient first.', sort_order: 157 },
  { id: 'dc-gcse-psolve-0158', deck_id: 'deck-gcse-problem-solving', front: 'How to find where a line intersects a circle.', back: '1. Substitute the line equation into the circle equation.\n2. Expand and simplify to get a quadratic.\n3. Solve the quadratic.\n4. Substitute back to find both (x,y) pairs.\n\nGCSE Tip: Discriminant of the quadratic tells you: 2 intersections (>0), tangent (=0), no intersection (<0).', sort_order: 158 },
  { id: 'dc-gcse-psolve-0159', deck_id: 'deck-gcse-problem-solving', front: 'How to apply the factor theorem (Higher GCSE/bridge to A-Level).', back: 'If f(a) = 0, then (x−a) is a factor of f(x).\nExample: f(x)=x³−7x+6. f(1)=1−7+6=0 → (x−1) is a factor.\nDivide to find remaining factors.\n\nGCSE Tip: Test small integers (±1, ±2, ...) to find a root quickly.', sort_order: 159 },
  { id: 'dc-gcse-psolve-0160', deck_id: 'deck-gcse-problem-solving', front: 'How to sketch the graph of y = 1/x and state its key features.', back: 'Shape: hyperbola in 1st and 3rd quadrants.\nAsymptotes: x=0 (y-axis) and y=0 (x-axis).\nNo x or y intercepts.\nSymmetric about y=x and y=−x.\n\nGCSE Tip: y=1/x is the standard reciprocal graph. y=k/x has the same shape, scaled by k.', sort_order: 160 },
  { id: 'dc-gcse-psolve-0161', deck_id: 'deck-gcse-problem-solving', front: 'How to find the nth term of a geometric sequence.', back: 'T(n) = ar^(n−1) where a = first term, r = common ratio.\nFind r by dividing any term by the previous one.\nExample: 2, 6, 18, 54... r=3, T(n) = 2×3^(n−1)\n\nGCSE Tip: Verify: T(1)=2×3⁰=2✓ T(2)=2×3¹=6✓', sort_order: 161 },
  { id: 'dc-gcse-psolve-0162', deck_id: 'deck-gcse-problem-solving', front: 'How to use the chain of inequality signs for compound inequalities.', back: 'Write x² > 4 as x > 2 OR x < −2 (not −2 < x < 2 which would be x²<4).\nFor x² < 4: it IS −2 < x < 2 (between the roots).\n\nGCSE Tip: Positive x²: > 0 → outside roots (OR); < 0 → between roots (AND).', sort_order: 162 },
  { id: 'dc-gcse-psolve-0163', deck_id: 'deck-gcse-problem-solving', front: 'How to find the area between two curves.', back: 'Area = ∫ₐᵇ [f(x)−g(x)] dx where f(x) is the upper curve.\n1. Find intersection points a and b.\n2. Subtract the lower function from the upper.\n3. Integrate and evaluate.\n\nGCSE Tip: Identify which curve is on top in the interval. Subtract lower from upper.', sort_order: 163 },
  { id: 'dc-gcse-psolve-0164', deck_id: 'deck-gcse-problem-solving', front: 'How to solve a proof question involving odd and even numbers.', back: 'Use algebraic representations:\nEven: 2n. Odd: 2n+1. Consecutive integers: n, n+1.\nConsecutive even: 2n, 2n+2. Consecutive odd: 2n+1, 2n+3.\n\nGCSE Tip: The strength of algebraic proof is in the GENERAL form. Never use specific numbers.', sort_order: 164 },
  { id: 'dc-gcse-psolve-0165', deck_id: 'deck-gcse-problem-solving', front: 'How to use function notation to find ff(x) or gf(x) for a general expression.', back: 'gf(x) = g(f(x)): substitute f(x) wherever g has an input.\nExample: f(x)=x+2, g(x)=x². gf(x) = g(x+2) = (x+2)².\nff(x) = f(f(x)) = f(x+2) = (x+2)+2 = x+4.\n\nGCSE Tip: gf: apply f first, then g. fg: apply g first, then f. Order matters!', sort_order: 165 },
  { id: 'dc-gcse-psolve-0166', deck_id: 'deck-gcse-problem-solving', front: 'Strategy: how to use "change of sign" to show a root lies in an interval.', back: 'Let f(x) = equation rearranged to = 0.\nEvaluate f(a) and f(b). If one is positive and one is negative → root between a and b (by continuity).\nMust state: "sign change therefore root in interval [a,b]".\n\nGCSE Tip: This is the formal way to justify your choice of starting interval for iteration.', sort_order: 166 },
  { id: 'dc-gcse-psolve-0167', deck_id: 'deck-gcse-problem-solving', front: 'How to find the domain and range of a function.', back: 'Domain: allowed input values (x values). Exclude values making denominator zero or square root negative.\nRange: possible output values (y values). Often found by considering the function\'s shape.\nExample: f(x)=√(x−3): domain x≥3; range f(x)≥0.\n\nGCSE Tip: Domain = input restrictions; Range = output possibilities.', sort_order: 167 },
  { id: 'dc-gcse-psolve-0168', deck_id: 'deck-gcse-problem-solving', front: 'How to use calculus to optimise (find maximum or minimum values).', back: '1. Write the quantity to optimise as a function of one variable.\n2. Differentiate and set dy/dx = 0.\n3. Solve for x.\n4. Use d²y/dx² to confirm max (negative) or min (positive).\n5. Calculate the optimal value.\n\nGCSE Tip: Common optimisation: maximum area given a fixed perimeter, minimum material for a given volume.', sort_order: 168 },
  { id: 'dc-gcse-psolve-0169', deck_id: 'deck-gcse-problem-solving', front: 'How to show that two triangles are congruent.', back: 'Use one of four conditions:\nSSS: three sides equal.\nSAS: two sides and included angle equal.\nASA or AAS: two angles and a corresponding side equal.\nRHS: right angle, hypotenuse and one side equal.\n\nGCSE Tip: State which condition you\'re using and label clearly which sides/angles correspond.', sort_order: 169 },
  { id: 'dc-gcse-psolve-0170', deck_id: 'deck-gcse-problem-solving', front: 'How to show that two triangles are similar.', back: 'Show one of:\n1. All three angles are equal (AAA).\n2. Two sides in the same ratio and the included angle equal (SAS similarity).\n3. All three sides in the same ratio (SSS similarity).\n\nGCSE Tip: Similarity → same shape, different size. Congruence → same shape AND size.', sort_order: 170 },
  { id: 'dc-gcse-psolve-0171', deck_id: 'deck-gcse-problem-solving', front: 'How to use the ambiguous case of the sine rule.', back: 'Given SSA (two sides and non-included angle), there may be two solutions.\nIf angle θ = sin⁻¹(k) where k<1 and θ<90°, the second solution is 180°−θ.\nCheck: does 180°−θ give a valid triangle (do all angles sum to 180° with angles>0)?\n\nGCSE Tip: Always check both solutions. Sketch both triangles to see which fits the context.', sort_order: 171 },
  { id: 'dc-gcse-psolve-0172', deck_id: 'deck-gcse-problem-solving', front: 'How to handle a "hence" question in an exam.', back: '"Hence" means: use the result of the previous part to answer this part.\nDon\'t start from scratch — identify how the earlier result feeds into this one.\n\nGCSE Tip: "Hence" is a clue: the previous answer (or method) is essential. Using it is usually the quickest approach.', sort_order: 172 },
  { id: 'dc-gcse-psolve-0173', deck_id: 'deck-gcse-problem-solving', front: 'How to prove a result about interior or exterior angles of a polygon.', back: 'Interior angle sum = (n−2)×180°\nProof strategy: split polygon into (n−2) triangles from one vertex. Each triangle contributes 180°.\n\nGCSE Tip: Draw the triangles inside the polygon. Label the angles and show they account for all interior angles.', sort_order: 173 },
  { id: 'dc-gcse-psolve-0174', deck_id: 'deck-gcse-problem-solving', front: 'How to use vectors to find a point that divides a line segment in a given ratio.', back: 'Point P divides AB in ratio m:n from A.\nOP = OA + (m/(m+n)) × AB\n= OA + (m/(m+n))(OB − OA)\n\nExample: ratio 2:3 from A → P = OA + (2/5)(OB−OA)\n\nGCSE Tip: The ratio tells you what fraction of AB to travel from A.', sort_order: 174 },
  { id: 'dc-gcse-psolve-0175', deck_id: 'deck-gcse-problem-solving', front: 'How to find a missing length using the ratio of similar solids.', back: 'For similar solids with length ratio k:1:\nLength ratio: k\nArea ratio: k²\nVolume ratio: k³\n\nExample: volumes 64cm³ and 125cm³. Length ratio = ³√(64/125) = 4/5.\n\nGCSE Tip: Always work from volume → cube root → length ratio. Don\'t just scale linearly.', sort_order: 175 },
  { id: 'dc-gcse-psolve-0176', deck_id: 'deck-gcse-problem-solving', front: 'How to complete the square to find the centre and radius of a circle.', back: 'x²+y²+ax+by+c=0: group x and y, complete the square for each.\nExample: x²+y²−6x+4y−3=0\n(x−3)²−9 + (y+2)²−4 −3=0\n(x−3)²+(y+2)²=16\nCentre (3,−2), radius 4.\n\nGCSE Tip: Complete the square on both x and y. Constant moves to the RHS = r².', sort_order: 176 },
  { id: 'dc-gcse-psolve-0177', deck_id: 'deck-gcse-problem-solving', front: 'How to approach a problem involving the graph of a function and its inverse.', back: 'The graph of f⁻¹(x) is a reflection of f(x) in the line y = x.\nIf a point (a,b) is on f, then (b,a) is on f⁻¹.\n\nGCSE Tip: f and f⁻¹ intersect on the line y=x (unless they touch elsewhere). Use this as a check.', sort_order: 177 },
  { id: 'dc-gcse-psolve-0178', deck_id: 'deck-gcse-problem-solving', front: 'How to find the x value where two exponential/power graphs intersect.', back: 'Set the equations equal: aˣ = bˣ or xᵃ = xᵇ.\nFor aˣ = bˣ: rearrange to (a/b)ˣ = 1 → x=0 if a≠b.\nFor more complex cases: take logs or use numerical methods.\n\nGCSE Tip: Try substituting simple values first (x=0, 1, 2) to find intersection points.', sort_order: 178 },
  { id: 'dc-gcse-psolve-0179', deck_id: 'deck-gcse-problem-solving', front: 'How to verify a solution using substitution in original simultaneous equations.', back: 'Substitute both x and y values into BOTH original equations.\nIf both equations balance → solution is correct.\nNever verify in a rearranged or derived equation.\n\nGCSE Tip: Checking in derived equations doesn\'t catch substitution errors. Use the originals.', sort_order: 179 },
  { id: 'dc-gcse-psolve-0180', deck_id: 'deck-gcse-problem-solving', front: 'How to solve a recurrence (iterative) sequence problem.', back: 'Given uₙ₊₁ = f(uₙ) and u₁:\nCalculate term by term: u₂=f(u₁), u₃=f(u₂), etc.\nFor a convergent sequence, terms approach a limit L where L = f(L). Solve for L.\n\nGCSE Tip: If the sequence is converging, the limit satisfies L = f(L). Set up and solve this equation.', sort_order: 180 },
  { id: 'dc-gcse-psolve-0181', deck_id: 'deck-gcse-problem-solving', front: 'How to sketch the derivative (gradient function) of a graph.', back: '1. Where f(x) has a maximum/minimum → f\'(x) = 0 (crosses x-axis).\n2. Where f(x) is increasing → f\'(x) > 0 (above x-axis).\n3. Where f(x) is decreasing → f\'(x) < 0 (below x-axis).\n\nGCSE Tip: Identify stationary points first. They become x-intercepts of the derivative graph.', sort_order: 181 },
  { id: 'dc-gcse-psolve-0182', deck_id: 'deck-gcse-problem-solving', front: 'How to use the trapezium rule to estimate area under a curve.', back: 'Area ≈ (h/2)[y₀ + 2(y₁+y₂+...+yₙ₋₁) + yₙ] where h = strip width.\nMore strips → better estimate.\nUnder a concave-up curve: trapezium rule overestimates.\n\nGCSE Tip: State whether your estimate is an overestimate or underestimate and why.', sort_order: 182 },
  { id: 'dc-gcse-psolve-0183', deck_id: 'deck-gcse-problem-solving', front: 'How to spot and factorise a "hidden" quadratic.', back: 'Example: x⁴−5x²+4=0. Let u=x²: u²−5u+4=0 → (u−1)(u−4)=0 → u=1 or u=4.\nSo x²=1 → x=±1; x²=4 → x=±2.\n\nGCSE Tip: If the powers are in ratio 2:1 (e.g. x⁴ and x²), substitute u=x² to get a standard quadratic.', sort_order: 183 },
  { id: 'dc-gcse-psolve-0184', deck_id: 'deck-gcse-problem-solving', front: 'How to handle a "find all values" trigonometric equation over a given range.', back: '1. Find the reference angle using inverse trig.\n2. Use CAST diagram or trig graphs to find all angles in range.\n3. Add 360° (or 180° for tan) repeatedly to find all solutions.\n\nGCSE Tip: Write down ALL solutions systematically. A list avoids missing solutions.', sort_order: 184 },
  { id: 'dc-gcse-psolve-0185', deck_id: 'deck-gcse-problem-solving', front: 'How to use the formula for the area of a parallelogram using vectors.', back: 'Area = |a × b| where a and b are adjacent side vectors.\nFor 2D: |a||b|sinθ where θ is the angle between them.\nExample: sides 4 and 7 with angle 60°: Area = 4×7×sin60° = 28×(√3/2) = 14√3\n\nGCSE Tip: Area = base × height = ab sinθ. Same formula as Area = (1/2)ab sinC for triangles (×2 for parallelogram).', sort_order: 185 },
  { id: 'dc-gcse-psolve-0186', deck_id: 'deck-gcse-problem-solving', front: 'How to find when a function is concave or convex using calculus.', back: 'Concave up (convex): d²y/dx² > 0.\nConcave down (concave): d²y/dx² < 0.\nPoint of inflection: where d²y/dx² changes sign.\n\nGCSE Tip: At a minimum: d²y/dx² > 0 (concave up). At a maximum: d²y/dx² < 0 (concave down).', sort_order: 186 },
  { id: 'dc-gcse-psolve-0187', deck_id: 'deck-gcse-problem-solving', front: 'Trick: how to use the "sum and product of roots" for a quadratic.', back: 'For ax²+bx+c=0:\nSum of roots = −b/a\nProduct of roots = c/a\n\nExample: x²−5x+6=0. Sum=5, Product=6. Roots are 2 and 3 (check: 2+3=5✓, 2×3=6✓).\n\nGCSE Tip: Fast way to check your solutions to a quadratic without expanding.', sort_order: 187 },
  { id: 'dc-gcse-psolve-0188', deck_id: 'deck-gcse-problem-solving', front: 'How to write a "counter-example" to disprove a statement.', back: 'To disprove: "All prime numbers are odd."\nCounter-example: 2 is prime and even. Statement is false.\n\nOnly ONE counter-example is needed to disprove a universal statement.\n\nGCSE Tip: Look for the simplest possible exception. Test small numbers or edge cases first.', sort_order: 188 },
  { id: 'dc-gcse-psolve-0189', deck_id: 'deck-gcse-problem-solving', front: 'How to prove two expressions are equivalent by expanding both sides.', back: 'Show LHS = RHS by simplifying independently.\nAlternatively: LHS − RHS = 0.\nExample: show (x+1)²−x² = 2x+1.\nLHS: x²+2x+1−x² = 2x+1 = RHS ✓\n\nGCSE Tip: When both sides are messy, expand both and show they simplify to the same thing.', sort_order: 189 },
  { id: 'dc-gcse-psolve-0190', deck_id: 'deck-gcse-problem-solving', front: 'How to interpret and use negative and fractional scale factors in enlargements.', back: 'Positive SF > 1: enlargement (same orientation).\nPositive 0 < SF < 1: reduction (same orientation).\nNegative SF: enlargement/reduction + rotation of 180° about the centre.\n\nExample: SF = −2: image is twice as large and on the opposite side of the centre.\n\nGCSE Tip: Negative SF → image is inverted. Multiply each distance from centre by |SF|.', sort_order: 190 },
  { id: 'dc-gcse-psolve-0191', deck_id: 'deck-gcse-problem-solving', front: 'How to find the gradient of a tangent to a curve at a point using first principles.', back: 'gradient = lim(h→0) [f(x+h)−f(x)]/h\nExample: f(x)=x²\n[f(x+h)−f(x)]/h = [(x+h)²−x²]/h = [2xh+h²]/h = 2x+h → 2x as h→0\n\nGCSE Tip: First principles reinforces why differentiation works. The limit removes the h term.', sort_order: 191 },
  { id: 'dc-gcse-psolve-0192', deck_id: 'deck-gcse-problem-solving', front: 'How to find the equation of a chord of a circle.', back: '1. Find the gradients from centre to each endpoint.\n2. Note that the chord\'s midpoint lies on the perpendicular bisector of the chord (which passes through the centre).\n3. Find the gradient of the chord, then use y−y₁=m(x−x₁).\n\nGCSE Tip: A chord is just a line segment — find it using the two-point gradient formula.', sort_order: 192 },
  { id: 'dc-gcse-psolve-0193', deck_id: 'deck-gcse-problem-solving', front: 'How to use "proof by contradiction" for GCSE.', back: '1. Assume the OPPOSITE of what you want to prove.\n2. Show this leads to a contradiction (something impossible or false).\n3. Conclude the original statement must be true.\n\nExample: Prove there\'s no largest prime. Assume there is a largest prime p. Construct p!+1, which has no prime factors ≤ p. Contradiction.\n\nGCSE Tip: State the assumption clearly at the start. The contradiction must be explicit.', sort_order: 193 },
  { id: 'dc-gcse-psolve-0194', deck_id: 'deck-gcse-problem-solving', front: 'How to use laws of indices to simplify complex expressions.', back: 'Key laws:\naᵐ × aⁿ = aᵐ⁺ⁿ\naᵐ ÷ aⁿ = aᵐ⁻ⁿ\n(aᵐ)ⁿ = aᵐⁿ\na⁰ = 1\na⁻ⁿ = 1/aⁿ\na^(m/n) = (ⁿ√a)ᵐ\n\nGCSE Tip: Apply one law at a time. Convert to the same base before comparing powers.', sort_order: 194 },
  { id: 'dc-gcse-psolve-0195', deck_id: 'deck-gcse-problem-solving', front: 'How to apply the circle theorems in multi-step problems.', back: 'Strategy:\n1. Identify all radii (mark as equal).\n2. Label the centre.\n3. List all circle theorems that might apply.\n4. Build up angles step by step, stating the theorem used each time.\n\nGCSE Tip: Show each step with the theorem name. Multi-step = multiple theorems. State reasons for every angle.', sort_order: 195 },
  { id: 'dc-gcse-psolve-0196', deck_id: 'deck-gcse-problem-solving', front: 'How to set up and solve optimisation problems.', back: 'Example: Maximise area of rectangle with perimeter 40m.\nLet width = x, length = 20−x (perimeter constraint)\nArea = x(20−x) = 20x−x²\ndA/dx = 20−2x = 0 → x=10\nSquare (10×10) has maximum area = 100m²\n\nGCSE Tip: Express the objective function in one variable using the constraint. Differentiate and set to zero.', sort_order: 196 },
  { id: 'dc-gcse-psolve-0197', deck_id: 'deck-gcse-problem-solving', front: 'How to recognise a "gradient trick" in a proportion proof.', back: 'To show y ∝ x: prove y/x = constant (or show the graph passes through the origin with a constant gradient).\nIf y/x = k for all data points → directly proportional.\n\nGCSE Tip: Direct proportion means the ratio y/x is always the same constant k.', sort_order: 197 },
  { id: 'dc-gcse-psolve-0198', deck_id: 'deck-gcse-problem-solving', front: 'How to handle an area or volume calculation with algebraic expressions.', back: 'Set up the expression, simplify, then solve.\nExample: Box has length (x+3), width x, height 4. Volume = 4x(x+3)=4x²+12x.\nIf volume=160: 4x²+12x−160=0 → x²+3x−40=0 → (x+8)(x−5)=0 → x=5 (reject −8).\n\nGCSE Tip: Form a quadratic from the volume/area, then solve. Reject negative lengths.', sort_order: 198 },
  { id: 'dc-gcse-psolve-0199', deck_id: 'deck-gcse-problem-solving', front: 'How to write a general proof about divisibility.', back: 'To prove "expression is divisible by k": show the expression equals k×(integer).\nExample: n²+n = n(n+1). One of n or n+1 is always even, so n(n+1) is always divisible by 2.\n\nGCSE Tip: Factorise to reveal the divisibility factor. Then argue why the remaining factor is always an integer.', sort_order: 199 },
  { id: 'dc-gcse-psolve-0200', deck_id: 'deck-gcse-problem-solving', front: 'Final strategy: how to approach a completely unfamiliar GCSE problem.', back: '1. READ carefully — underline key information.\n2. DRAW a diagram if geometry.\n3. LABEL what you know and what you need.\n4. DECIDE which topic area it falls under.\n5. APPLY the relevant formula or technique.\n6. CHECK your answer makes sense in context.\n\nGCSE Tip: Almost every GCSE problem uses a familiar technique in an unfamiliar context. Identify the technique.', sort_order: 200 },
];
